const inputData = $input.first().json; 
const texto_bruto = inputData.output || inputData.text || "";

// Extrae el texto completo de la variable
const extraerTexto = (campo, fallback) => {
    const regex = new RegExp(`${campo}[:\\s]+([^\\n]+)`, 'i');
    const match = texto_bruto.match(regex);
    return match ? match[1].trim() : fallback;
};

// NUEVO: Agarra solo el PRIMER número de la lista separada por comas para BigQuery
const extraerPrimerNumero = (campo, fallback) => {
    const texto = extraerTexto(campo, "");
    if (!texto) return fallback;
    const primerNumero = texto.split(',')[0].trim(); 
    return parseFloat(primerNumero.replace(',', '.')) || fallback;
};

const reporte_limpio = texto_bruto.replace(/\[MOSTRAR_GRAFICO\][\s\S]*/i, "").trim();

return [{
    json: {
        // --- DATOS PARA BIGQUERY ---
        timestamp: new Date().toISOString(),
        session_id: inputData.session_id || `agro-${Date.now()}`,
        sector: "AGRO", 

        cultivo: extraerTexto("cultivo", "S/D"),
        region: extraerTexto("region", "S/D"),
        temperatura_suelo: extraerPrimerNumero("temperatura_suelo", 18),
        humedad_relativa: extraerPrimerNumero("humedad_relativa", 50),
        precipitacion: extraerPrimerNumero("precipitacion", 0),
        horas_sol: extraerPrimerNumero("horas_sol", 8),
        fase_lunar: extraerTexto("fase_lunar", "S/D"),

        ai_recommendations: reporte_limpio,
        metadata: JSON.stringify({ status: "success" }),

        // --- DATOS PARA EL FRONTEND (Lleva las listas completas) ---
        output: texto_bruto 
    }
}];
